/**
 * helixa-reporter.ts — PACT Chamber 4 Soul Handshake
 * Reports session outcomes to Helixa so it can update long-term agent trust scores.
 * Endpoint: POST https://api.helixa.xyz/api/v2/session/outcome
 * Auth: Bearer JWT (PACT session JWT)
 * Per decisions-2026-03-30.md Q3 + Q4: trust_delta = ±2, minimal format.
 */
import * as https from 'https';

const HELIXA_HOST = 'api.helixa.xyz';
const HELIXA_PATH = '/api/v2/session/outcome';
const TIMEOUT_MS = 8000;

export type SessionOutcome = 'success' | 'partial' | 'failed';

export interface SoulHandshake {
  session_id: string;
  outcome: SessionOutcome;
  trust_delta: number; // ±2 per decision Q4
}

/**
 * Report session outcome to Helixa (Chamber 4 Soul Handshake).
 * Non-throwing: logs errors but does not propagate.
 * @param sessionId   PACT session ID
 * @param outcome     'success' | 'partial' | 'failed'
 * @param trustDelta  Signed integer, typically +2 (success) or -2 (failed)
 * @param jwt         PACT session JWT for Authorization header
 */
export async function reportSessionOutcome(
  sessionId: string,
  outcome: SessionOutcome,
  trustDelta: number,
  jwt: string,
): Promise<void> {
  const payload: SoulHandshake = { session_id: sessionId, outcome, trust_delta: trustDelta };
  const data = JSON.stringify(payload);
  return new Promise((resolve) => {
    const req = https.request(
      {
        hostname: HELIXA_HOST, path: HELIXA_PATH, method: 'POST',
        timeout: TIMEOUT_MS,
        headers: {
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(data),
          'Authorization': `Bearer ${jwt}`,
        },
      },
      (res) => {
        let body = '';
        res.on('data', (c: string) => { body += c; });
        res.on('end', () => {
          console.info(`[helixa-reporter] ${sessionId} outcome=${outcome} delta=${trustDelta} HTTP=${res.statusCode}`);
          resolve();
        });
      },
    );
    req.on('timeout', () => {
      console.warn(`[helixa-reporter] ${sessionId} timeout after ${TIMEOUT_MS}ms`);
      req.destroy(); resolve();
    });
    req.on('error', (err) => {
      console.error(`[helixa-reporter] ${sessionId} error: ${err.message}`);
      resolve();
    });
    req.write(data); req.end();
  });
}
